const intentResponse = $input.first().json;
const content = intentResponse.content?.[0]?.text || '{}';
let intent;
try { intent = JSON.parse(content); } catch(e) {
  const match = content.match(/\{[\s\S]*\}/);
  intent = match ? JSON.parse(match[0]) : {intent: 'otro', confidence: 0.5};
}
const context = $('Read Context').first().json;
return [{
  json: {
    intent: intent.intent,
    confidence: intent.confidence,
    extracted: intent.extracted || {},
    text: context.text,
    profile: context.profile,
    ratingsHistory: context.ratingsHistory,
    lastDigest: context.lastDigest
  }
}];

